Context("Fraction");
Context()->flags->set(reduceConstants => 0);
Context()->operators->redefine('>',using=>',',from=>'Numeric');
Context()->lists->set('List' => {separator => '>'});

@a = (-7.6, 6, -6, 9.5, 8);
$as = '{' . join('}\quad{', @a) . '}';
@b = PGsort(sub{$_[0] > $_[1]}, @a);
$bs = join('>', @b);

@a2 = (Real(-5.2), Compute("pi"), Fraction(10, 3), Real(4.6), Real(8));
$as2 = '{' . join('}\quad{', map{$_->TeX} (@a2)) . '}';
@b2 = PGsort(sub{Real("$_[0]") > Real("$_[1]")}, @a2);
$bs2 = join('>', @b2);

$comparison = Compute("$bs");
$comparison2 = Compute("$bs2");
$evaluator = $comparison->cmp(ordered => 1);
$evaluator2 = $comparison2->cmp(ordered => 1);

$image_1 = createLaTeXImage();
$image_1->addToPreamble(latexImagePreamble());
$image_1->BEGIN_LATEX_IMAGE
